<style scoped>
.badge {
	will-change: transform;
	backface-visibility: hidden;
	animation: int-float 3.5s ease-in-out infinite;
}

.badge-tl { animation-delay: 0s; }
.badge-tr { animation-delay: 0.4s; }
.badge-l  { animation-delay: 0.8s; }
.badge-r  { animation-delay: 1.2s; }
.badge-bc { animation-delay: 1.6s; }

@keyframes int-float {
	0%, 100% { transform: translate3d(0, 0, 0); }
	50%       { transform: translate3d(0, -7px, 0); }
}

@media (prefers-reduced-motion: reduce) {
	.badge {
		animation: none;
	}
}
</style>
